#include <iostream>
#include <vector>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    // dp[i][j] = number of ways to get sum j using i dice (or rather,
    // we want combinations with repetition: C(n+6-1, 6-1) = C(n+5, 5)
    // But let's use DP: dp[face][count] for clarity.
    // Use 64-bit; max n=50 => C(55,5)=3,478,761 fits in 64-bit.
    // Actually C(55,5) = 3,478,761 fits in 32-bit too, but 64-bit is safe.

    // Method: stars and bars: number of nonnegative integer solutions to
    // x1+x2+...+x6 = n is C(n+5,5). Let's compute via DP for clarity.
    // dp[i][s] = ways with first i faces summing to s
    // dp[0][0] = 1
    // dp[i][s] = sum_{t=0..min(n-s, ...)} dp[i-1][s-t] ... but easier:
    // 1D DP: dp[s] = ways to distribute sum s among 6 faces.

    vector<long long> dp(n + 1, 0);
    dp[0] = 1;  // 0 dice -> 1 way (empty outcome)
    for (int face = 0; face < 6; ++face) {
        vector<long long> ndp(n + 1, 0);
        for (int s = 0; s <= n; ++s) {
            // for each possible count t assigned to this face
            for (int t = 0; t <= n - s; ++t) {
                ndp[s + t] += dp[s];
            }
        }
        dp = move(ndp);
    }
    cout << dp[n] << "\n";

    return 0;
}
